const body = ($json.body && typeof $json.body === 'object') ? $json.body : {};
const user_id = (body.user_id || '').trim();
if (!user_id) throw new Error('user_id is required');
const uuidRe = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (!uuidRe.test(user_id)) throw new Error('user_id must be a valid UUID');
const has_description = 'manager_description' in body;
const manager_description = has_description
  ? (body.manager_description !== null ? String(body.manager_description).substring(0, 5000) : null)
  : null;
return [{ json: { user_id, manager_description, has_description } }];

const params = $('Build Params').item.json;
const orgId = $json.managed_org_id;
function esc(s) { return "'" + String(s).replace(/'/g, "''") + "'"; }
const parts = ['updated_at = now()'];
if (params.has_description) {
  const desc = params.manager_description !== null ? esc(params.manager_description) : 'NULL';
  parts.push('manager_description = ' + desc);
}
const sql = "UPDATE sc_orgs SET " + parts.join(', ') + " WHERE org_id = '" + orgId + "'::uuid RETURNING org_id::text, slug";
return [{ json: { sql } }];
